import base64

p12_b64 = """"""

try:
    decoded = base64.b64decode(p12_b64)
    print(f"Decoded size: {len(decoded)} bytes")
    print(f"First 4 hex bytes: {decoded[:4].hex()}")
    # Check for PKCS12 magic / ASN.1
    if decoded[:2] == b'0\x82':
        print("✓ Valid ASN.1 SEQUENCE (looks like PKCS12)")
    else:
        print(f"⚠ Unexpected header: {decoded[:10].hex()}")
except Exception as e:
    print(f"✗ Invalid base64: {e}")
